            return args
        # Long-option attached: --attr=value
        if a.startswith("--") and "=" in a:
            key, _, val = a[2:].partition("=")
            if key == "attribute":
                args["attribute"] = val
            elif key == "base":
                args["base"] = val
            elif key == "filename":
                args["filename"] = val
            elif key == "output":
                args["output"] = val
            elif key == "remove-nodes":
                args["remove_nodes"].append(val)
            else:
                args["_error"] = f"Found argument '{a}' which wasn't expected"
                return args
            i += 1
            continue
        # Short option with separate value, or long option.
        if a in ("-a", "--attribute"):
            if i + 1 >= len(argv):
                args["_error"] = f"option '{a}' requires a value"
                return args
            args["attribute"] = argv[i + 1]
            i += 2
            continue
        if a in ("-b", "--base"):
            if i + 1 >= len(argv):
                args["_error"] = f"option '{a}' requires a value"
                return args
            args["base"] = argv[i + 1]
            i += 2
            continue
        if a in ("-f", "--filename"):
            if i + 1 >= len(argv):
                args["_error"] = f"option '{a}' requires a value"
                return args
            args["filename"] = argv[i + 1]
            i += 2
            continue
        if a in ("-o", "--output"):
            if i + 1 >= len(argv):
                args["_error"] = f"option '{a}' requires a value"
                return args
            args["output"] = argv[i + 1]
            i += 2
            continue
        if a in ("-r", "--remove-nodes"):
            # Greedy: take all following positionals until next flag.
            i += 1
            if i >= len(argv):
                args["_error"] = f"option '{a}' requires a value"
                return args
            args["remove_nodes"].append(argv[i])
            i += 1
            while i < len(argv) and not argv[i].startswith("-") and argv[i] != "--":
                args["remove_nodes"].append(argv[i])
                i += 1
            continue
        if a.startswith("-"):
            args["_error"] = f"Found argument '{a}' which wasn't expected"
            return args
        # Positional.
        args["selectors"].append(a)
        i += 1
    return args


