# ============================================================
# Main
# ============================================================

def main(argv):
    args = parse_args(argv)

    if args["help"]:
        sys.stdout.write(HELP_TEXT)
        return 0
    if args["version"]:
        sys.stdout.write(VERSION_TEXT)
        return 0
    if args["_error"]:
        sys.stderr.write(f"error: {args['_error']}, or isn't valid in this context\n\n")
