# Element categorization (per HTML5 spec / kuchiki / htmlq)
# ============================================================

VOID_ELEMENTS = {
    "area", "base", "basefont", "bgsound", "br", "col", "embed", "frame",
    "hr", "img", "input", "keygen", "link", "meta", "param", "source",
    "track", "wbr",
}

RAW_TEXT_ELEMENTS = {
    "style", "script", "xmp", "iframe", "noembed", "noframes", "plaintext",
}

